#pragma mark - Routing

- (void)jun_routeBuild:(JUNRouteBuilder *)route {

    [route name:@"launch" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        [self switchToHomeVC];
        [self extractRouteParamsBasicSuiteWithDict:userInfo next:^(NSInteger vappId, BOOL hard) {
            WBVAppModel *vapp = [self getLocalVAppById:vappId];
            NSParameterAssert(vapp);
            if (!vapp) return;
            WBHomeViewController *homeVC = [self getHomeVC];
            if (hard) { // Set hard to true only skip action request and vip check now.
//                vapp.authorized = true;
                homeVC.skipActionRequestWhenLaunch = true;
                homeVC.skipVIPCheckWhenLaunch = true;
            }
            id notifValue = userInfo[@"isNotifOn"];
            if (notifValue && ![notifValue isKindOfClass:[NSNull class]]) {
                BOOL isNotifOn = [notifValue boolValue];
                if (isNotifOn) {
                    vapp.featureStatusInfo.isNotificationSwitchOn = YES;
                    [WBVAppManager.sharedManager saveBackgroundSetting:YES forVApp:vapp];
                } else {
                    vapp.featureStatusInfo.isNotificationSwitchOn = NO;
                    [WBVAppManager.sharedManager saveBackgroundSetting:NO forVApp:vapp];
                }
            }
            [homeVC launchVappWithVappStatusCheck:vapp];
        }];
    }];

    [route name:@"get" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        [self switchToHomeVC];
        [self extractRouteParamsBasicSuiteWithDict:userInfo next:^(NSInteger vappId, BOOL hard) {
            [[self getHomeVC] getVappWithId:vappId hard:hard];
        }];
    }];

    [route name:@"reserve" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        [self extractRouteParamsBasicSuiteWithDict:userInfo next:^(NSInteger vappId, BOOL hard) {
            [self dismissAllPresentedViewControllers];
            [[self getHomeVC] reserveVappWithId:vappId hard:hard];
        }];
    }];

    [route name:@"apns" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        NSInteger vappId = [userInfo[@"id"] integerValue];
        NSString *type = userInfo[@"type"]; // 开or关
        NSString *urlStr = [NSString stringWithFormat:@"webox:///page/mine/settings/vapp?id=%zd", vappId];
        NSURL *url = [NSURL URLWithString:urlStr];
        [[WBRouteManager sharedManager] performRoute:url completion:^(id<JUNRouter>  _Nonnull lastRouter) {
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.3 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                UIViewController *settingGlobalVC = (UIViewController *)lastRouter;
                BOOL desiredOn = ![type isKindOfClass:[NSString class]] || ![(NSString *)type isEqualToString:@"off"];
                WBVAppModel *vapp = [self getLocalVAppById:vappId];
                if (!vapp) { return; }
                BOOL currentOn = vapp.featureStatusInfo.isNotificationSwitchOn;
                if (desiredOn != currentOn) {
                    [[WBBenefitManager sharedManager] toggleNotificationForVapp:vapp
                                                                     presenter:settingGlobalVC
                                                                     setSwitch:^(BOOL on, BOOL animated) {}];
                }
            });
        } sourceInterface:nil];
        next(nil);
    }];

}

/// Route params basic suite, which looks like 'id=${arg1: Int}&hard=${arg2: bool}'
/// - Parameters:
///   - userInfo: Parameter dict in route.
///   - nextHandler: Parsed result handler.
- (void)extractRouteParamsBasicSuiteWithDict:(NSDictionary *)userInfo next:(void (^)(NSInteger vappId, BOOL isHard))nextHandler {
    if (!nextHandler) return;
    NSInteger vappId = [userInfo[@"id"] integerValue];
    BOOL isHard = [userInfo[@"hard"] boolValue];
    nextHandler(vappId, isHard);
}

